import { TextField } from ':components/TextField';
import { useCombinedRef } from ':helpers/use-combined-ref';
import React, { forwardRef, useCallback, useEffect, useImperativeHandle, useMemo, useRef } from 'react';
import { useIMask } from 'react-imask';

import type { NewMaskFieldProps } from './NewMaskField.types';

export const NewMaskField = forwardRef<HTMLInputElement, NewMaskFieldProps>(
	(
		{
			size = 'medium',
			autoComplete = 'off',
			inputClassName: externalInputClassName,
			fullWidth = false,
			error = false,
			disabled = false,
			dataTestId = 'TextField',
			isClickableAdornment = true,
			maskConfig,
			onChange,
			value: inputValue,
			defaultValue,
			label,
			placeholder,
			onMaskRef,
			onComplete,
			...props
		},
		ref,
	) => {
		const localRef = useRef<HTMLInputElement>(null);
		const isInitializedRef = useRef(false);
		useImperativeHandle(ref, () => localRef.current);

		const onChangeRef = useRef(onChange);
		onChangeRef.current = onChange;

		const onCompleteRef = useRef(onComplete);
		onCompleteRef.current = onComplete;

		const handleAccept = useCallback((value: string, mask: any, event: InputEvent) => {
			if (!isInitializedRef.current) return;

			// Если в ивенте value пустое, то считаем, что пользователь очистил инпут
			// Это фиксит проблему в тестах, когда imask возвращает старое значение при очистке
			const target = event?.target as HTMLInputElement;

			if (target && target.value === '') {
				onChangeRef.current?.('', '', event);
				return;
			}

			onChangeRef.current?.(value, mask.unmaskedValue, event);
		}, []);

		const handleComplete = useCallback((value: string, mask: any, event: InputEvent) => {
			onCompleteRef.current?.(value, mask, event);
		}, []);

		// Настройка конфигурации маски с поддержкой placeholder
		const enhancedMaskConfig = useMemo(() => {
			if (!maskConfig) {
				return maskConfig;
			}

			// Если есть и label, и placeholder, используем placeholder как placeholderChar для маски
			if (label && placeholder && typeof maskConfig === 'object') {
				return {
					...maskConfig,
					lazy: false, // Показывать маску всегда
					placeholderChar: '_', // Символ замещения
				};
			}

			return maskConfig;
		}, [maskConfig, label, placeholder]);

		const imaskOptions = useMemo(
			() => ({
				onAccept: handleAccept,
				onComplete: handleComplete,
			}),
			[handleAccept, handleComplete],
		);

		const {
			ref: IMaskRef,
			value,
			unmaskedValue,
			setUnmaskedValue,
			setValue,
			maskRef,
			typedValue,
			setTypedValue,
		} = useIMask(enhancedMaskConfig, imaskOptions);

		maskRef.current?.alignCursorFriendly();

		// Устанавливаем начальное значение при монтировании
		useEffect(() => {
			const initialValue = inputValue ?? defaultValue;
			if (initialValue !== undefined && initialValue !== null) {
				setValue(initialValue.toString());
			}
			isInitializedRef.current = true;
		}, []); // Выполняется только при монтировании

		const prevInputValueRef = useRef(inputValue);

		// Обновляем значение при изменении inputValue (контролируемый режим)
		useEffect(() => {
			if (inputValue !== prevInputValueRef.current) {
				prevInputValueRef.current = inputValue;
				if (inputValue !== undefined && inputValue !== null) {
					setValue(inputValue.toString());
				}
			}
		}, [inputValue, setValue]);

		// Определяем, какой placeholder использовать
		const effectivePlaceholder = useMemo(() => {
			// Если есть label, не показываем placeholder в TextField (он будет скрыт CSS)
			// Маска сама покажет символы замещения
			if (label) {
				return;
			}
			// Если нет label, используем placeholder как обычно
			return placeholder;
		}, [label, placeholder]);

		useEffect(() => {
			if (onMaskRef) {
				onMaskRef(maskRef);
			}
		}, [onMaskRef, maskRef]);

		return (
			<div data-testid="MaskField">
				<TextField
					ref={useCombinedRef(localRef, IMaskRef)}
					size={size}
					onChange={e => {
						// Фикс для тестов и ситуаций, когда нативное событие input не срабатывает (например fireEvent.change),
						// но React событие change срабатывает. Если значение пустое, форсируем вызов handleAccept.
						if (e.target.value === '') {
							handleAccept('', maskRef.current, e.nativeEvent as InputEvent);
						}
					}}
					autoComplete={autoComplete}
					inputClassName={externalInputClassName}
					fullWidth={fullWidth}
					error={error}
					disabled={disabled}
					dataTestId={dataTestId}
					isClickableAdornment={isClickableAdornment}
					label={label}
					placeholder={effectivePlaceholder}
					{...props}
				/>
			</div>
		);
	},
);
